mapper.select:
SELECT a.id AS course_id, a.course_name, a.course_type AS practice_type, d.name AS practice_type_name FROM xm_course a LEFT JOIN sys_data_dictionary_item d ON d.dictionary_code = '0006' AND d.value = a.course_type AND d.is_delete = 0 WHERE a.is_delete = 0 AND EXISTS (SELECT 1 FROM xm_course_question WHERE a.id = course_id AND is_delete = 0)
AND a.course_type = #{type}
AND a.course_name LIKE CONCAT('%', #{name}, '%')
